import { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import ReactQuill from 'react-quill-new';
import 'react-quill-new/dist/quill.snow.css';
import API from '../config/api';
import toast from 'react-hot-toast';

export default function EditPost() {
  const { id } = useParams();
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [excerpt, setExcerpt] = useState('');
  const [coverImage, setCoverImage] = useState('');
  const [category, setCategory] = useState('');
  const [tags, setTags] = useState('');
  const [status, setStatus] = useState('draft');
  const [categories, setCategories] = useState([]);
  const [uploading, setUploading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    fetchPost();
    fetchCategories();
  }, [id]);

  const fetchPost = async () => {
    try {
      // We need to fetch by ID, so let's get all posts and find ours
      const { data } = await API.get('/posts?status=all&limit=100');
      const post = data.posts.find((p) => p._id === id);
      if (post) {
        setTitle(post.title);
        setContent(post.content);
        setExcerpt(post.excerpt || '');
        setCoverImage(post.coverImage || '');
        setCategory(post.category?._id || '');
        setTags(post.tags?.join(', ') || '');
        setStatus(post.status);
      }
    } catch (err) {
      toast.error('Failed to load post');
    }
    setLoading(false);
  };

  const fetchCategories = async () => {
    try {
      const { data } = await API.get('/categories');
      setCategories(data.categories);
    } catch (err) {
      console.error(err);
    }
  };

  const handleImageUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const formData = new FormData();
    formData.append('image', file);

    setUploading(true);
    try {
      const { data } = await API.post('/upload', formData);
      setCoverImage(data.url);
      toast.success('Image uploaded!');
    } catch (err) {
      toast.error('Upload failed');
    }
    setUploading(false);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!title || !content) {
      return toast.error('Title and content are required');
    }

    setSaving(true);
    try {
      await API.put(`/posts/${id}`, {
        title,
        content,
        excerpt,
        coverImage,
        category: category || undefined,
        tags: tags.split(',').map((t) => t.trim()).filter(Boolean),
        status,
      });
      toast.success('Post updated!');
      navigate('/posts');
    } catch (err) {
      toast.error('Failed to update post');
    }
    setSaving(false);
  };

  const modules = {
    toolbar: [
      [{ header: [1, 2, 3, false] }],
      ['bold', 'italic', 'underline', 'strike'],
      [{ list: 'ordered' }, { list: 'bullet' }],
      ['blockquote', 'code-block'],
      ['link', 'image'],
      ['clean'],
    ],
  };

  if (loading) {
    return <div className="page-loader"><div className="loader"></div></div>;
  }

  return (
    <div className="create-post-page">
      <h1 className="page-title">Edit Post</h1>

      <form onSubmit={handleSubmit} className="post-form">
        <div className="form-main">
          <div className="form-group">
            <label>Title</label>
            <input
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder="Enter post title..."
              required
            />
          </div>

          <div className="form-group">
            <label>Content</label>
            <ReactQuill
              theme="snow"
              value={content}
              onChange={setContent}
              modules={modules}
              placeholder="Write your post content..."
              className="quill-editor"
            />
          </div>

          <div className="form-group">
            <label>Excerpt</label>
            <textarea
              value={excerpt}
              onChange={(e) => setExcerpt(e.target.value)}
              placeholder="Brief summary of the post..."
              rows={3}
            />
          </div>
        </div>

        <div className="form-sidebar">
          <div className="form-card">
            <h3>Publish</h3>
            <div className="form-group">
              <label>Status</label>
              <select value={status} onChange={(e) => setStatus(e.target.value)}>
                <option value="draft">Draft</option>
                <option value="published">Published</option>
              </select>
            </div>
            <button type="submit" className="btn btn-primary btn-full" disabled={saving}>
              {saving ? 'Saving...' : 'Update Post'}
            </button>
          </div>

          <div className="form-card">
            <h3>Cover Image</h3>
            {coverImage && (
              <img src={coverImage} alt="Cover" className="cover-preview" />
            )}
            <label className="file-upload-btn">
              {uploading ? 'Uploading...' : 'Upload Image'}
              <input type="file" accept="image/*" onChange={handleImageUpload} hidden />
            </label>
          </div>

          <div className="form-card">
            <h3>Category</h3>
            <select value={category} onChange={(e) => setCategory(e.target.value)}>
              <option value="">Select category</option>
              {categories.map((cat) => (
                <option key={cat._id} value={cat._id}>{cat.name}</option>
              ))}
            </select>
          </div>

          <div className="form-card">
            <h3>Tags</h3>
            <input
              type="text"
              value={tags}
              onChange={(e) => setTags(e.target.value)}
              placeholder="tag1, tag2, tag3"
            />
          </div>
        </div>
      </form>
    </div>
  );
}

